module RefModule(
	input clk,
	input reset_n,
	output reg enable);reg [2:0] obf_count;

always @(posedge clk or negedge reset_n) begin
	if (!reset_n) begin
		obf_count <= 3'b000;
		enable <= 0;
	end else if (obf_count == 3'b100) begin
		obf_count <= 3'b000;
		enable <= 1;
	end else begin
		obf_count <= obf_count + 1;
		enable <= 0;
	end
end

endmodule
